import React, { useState, useEffect } from 'react';
import StatCards from '../components/StatCards';
import InvestigationPanel from '../components/InvestigationPanel';
import Timeline from '../components/Timeline';
import AttackChart from '../components/AttackChart';
import AttackMap from '../components/AttackMap';
import DetailedModal from '../components/DetailedModal';

const MainSOC = () => {
  const [latestThreat, setLatestThreat] = useState(null);
  const [threatHistory, setThreatHistory] = useState([]);
  
  // State for handling the modal popup
  const [modalData, setModalData] = useState({ isOpen: false, title: '' });

  const generateRealisticData = () => {
    const attacks = ['DDoS', 'Phishing', 'Ransomware', 'Botnet', 'Port Scan', 'Zero-Day Exploit', 'Normal'];
    const countries = ['Russia', 'China', 'USA', 'Brazil', 'India'];
    const attackerIps = ['192.168.1.50', '45.22.11.9', '114.55.20.1', '8.8.8.8', '203.0.113.5'];
    const isAttack = Math.random() > 0.3; // 70% chance of attack for active demo
    
    return {
      timestamp: Date.now() / 1000,
      source_ip: attackerIps[Math.floor(Math.random() * attackerIps.length)],
      origin_country: countries[Math.floor(Math.random() * countries.length)],
      attack_type: isAttack ? attacks[Math.floor(Math.random() * (attacks.length - 1))] : 'Normal',
      threat_score: isAttack ? (Math.random() * (0.99 - 0.7) + 0.7).toFixed(2) : 0.12,
      severity: isAttack ? 'CRITICAL' : 'LOW'
    };
  };

  useEffect(() => {
    const interval = setInterval(() => {
      const data = generateRealisticData();
      setLatestThreat(data);
      setThreatHistory(prev => [data, ...prev].slice(0, 10)); // Keep last 10 events
    }, 2500); // Updates every 2.5 seconds
    return () => clearInterval(interval);
  }, []);

  const handleCardClick = (id, title) => {
    setModalData({ isOpen: true, title: title });
  };

  return (
    <div style={{ backgroundColor: '#0b0f19', minHeight: '100vh', color: 'white', padding: '20px' }}>
      
      {/* Renders the modal when a stat card or button is clicked */}
      {modalData.isOpen && (
        <DetailedModal title={modalData.title} onClose={() => setModalData({ isOpen: false, title: '' })} />
      )}

      <header style={{ borderBottom: '1px solid #334155', paddingBottom: '15px', marginBottom: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1 style={{ color: '#00ff9d', margin: 0, textShadow: '0 0 10px rgba(0,255,157,0.3)' }}>CortexShield SOC</h1>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <button onClick={() => handleCardClick('database', 'Global Threat Database')} style={{ background: '#3b82f6', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '4px', cursor: 'pointer', fontWeight: 'bold' }}>
            View Full Database
          </button>
          <span style={{ color: '#ef4444', fontSize: '14px', fontWeight: 'bold', animation: 'pulse 2s infinite' }}>● LIVE SYSTEM ACTIVE</span>
          <button onClick={() => { window.location.href='/'; }} style={{ background: 'transparent', color: '#ef4444', border: '1px solid #ef4444', padding: '5px 15px', borderRadius: '4px', cursor: 'pointer' }}>
            Disconnect
          </button>
        </div>
      </header>

      {/* Passing the click handler to the cards */}
      <StatCards onCardClick={handleCardClick} />

      <div style={{ display: 'flex', gap: '20px', margin: '20px 0' }}>
        <div style={{ flex: 2, background: '#1a1f2e', height: '400px', borderRadius: '12px', overflow: 'hidden', border: '1px solid #334155' }}>
          <AttackMap currentThreat={latestThreat} />
        </div>
        <div style={{ flex: 1, background: '#1a1f2e', height: '400px', borderRadius: '12px', padding: '20px', border: '1px solid #334155' }}>
          <AttackChart />
        </div>
      </div>

      <div style={{ display: 'flex', gap: '20px' }}>
        <div style={{ flex: 1, background: '#1a1f2e', height: '350px', borderRadius: '12px', padding: '20px', border: '1px solid #334155' }}>
          <InvestigationPanel currentThreat={latestThreat} />
        </div>
        <div style={{ flex: 1, background: '#1a1f2e', height: '350px', borderRadius: '12px', padding: '20px', overflowY: 'auto', border: '1px solid #334155' }}>
          <h3 style={{ margin: '0 0 15px 0', color: 'white', borderBottom: '1px solid #334155', paddingBottom: '10px' }}>Live Attack Timeline</h3>
          <Timeline history={threatHistory} />
        </div>
      </div>
    </div>
  );
};

export default MainSOC;
